+        assert_eq!(FsEmbedder::model_name(&adapter), "trait-stub");
+        assert!(FsEmbedder::is_semantic(&adapter));
+        assert_eq!(FsEmbedder::category(&adapter), FsModelCategory::StaticEmbedder);
+    }
